mapper.insert:
/* ReuseRipMgmtMapper.insertReuseRipMst */
INSERT INTO MSP_REUSE_IP_MST(
	REUSE_IP_SEQ
	,CONTRACT_NUM
	,RIP
	,RIP_STATUS
	,REG_RSN
	,REGST_ID
	,REGST_DTTM
)VALUES(
    REUSE_IP_SEQ.NEXTVAL
	,#{contractNum, jdbcType=VARCHAR}
	,(SELECT RIP FROM MCP_REQUEST@DL_MCP WHERE REQUEST_KEY  = #{requestKey, jdbcType=VARCHAR})
	,#{ripStatus, jdbcType=VARCHAR}
	,#{regRsn, jdbcType=VARCHAR}
	,#{sessionUserId}
	, SYSDATE
)

		/* ReuseRipMgmtMapper.insertReuseRipHist */
	INSERT INTO MSP_REUSE_IP_HIST(
			CONTRACT_NUM
			,RIP
			,RIP_STATUS
			,REG_RSN
            ,RATE_CD
            ,SUB_STATUS
			,REGST_ID
			,REGST_DTTM
		)VALUES(
			#{contractNum, jdbcType=VARCHAR}
			,(SELECT RIP FROM MCP_REQUEST@DL_MCP WHERE REQUEST_KEY  = #{requestKey, jdbcType=VARCHAR})
			,#{ripStatus, jdbcType=VARCHAR}
			,#{regRsn, jdbcType=VARCHAR}
            ,#{lstRateCd, jdbcType=VARCHAR}
            ,#{subStatus, jdbcType=VARCHAR}
			,#{sessionUserId}
			, SYSDATE
		)

mapper.select:
/* ReuseRipMgmtMapper.selectReuseRipList */
SELECT RE.REUSE_IP_SEQ /*일려번호*/ , REQ.REQUEST_KEY /*REQUEST_KEY*/ ,RE.CONTRACT_NUM /*계약번호*/ --,RE.RIP ,SUB.SUBSCRIBER_NO ,SUB.SUB_LINK_NAME ,REQ.REQ_BUY_TYPE_NM ,REQ.OPER_TYPE_NM ,REQ.FST_RATE_CD ,REQ.FST_RATE_NM ,REQ.LST_RATE_CD ,REQ.LST_RATE_NM ,SUB.SUB_STATUS ,FN_GET_CODENM('MSP0003' , SUB.SUB_STATUS) AS SUB_STATUS_NM ,CASE WHEN SUB.SUB_STATUS = 'C' THEN CASE WHEN 0 = TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '당일개통취소' WHEN 15 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '14일이내해지' WHEN 90 > TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS CAN_RSN ,FN_GET_CODENM('RCP0007', REQ.ON_OFF_TYPE) AS ON_OFF_TYPE_NM ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = SUB.OPEN_AGNT_CD AND ROWNUM = 1) AS OPEN_AGNT_NM ,TO_CHAR(TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS LST_COM_ACTV_DATE ,TO_CHAR(TO_DATE(DECODE(SUB.SUB_STATUS,'C',SUBSTR(SUB.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS CAN_DATE ,CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM(PUM.ORGN_ID) END AS USIM_ORG_NM ,FN_GET_ORGNM(PUM.ORGN_ID) AS FST_USIM_ORG_NM ,FN_GET_CODENM('RCP2001', R.ONLINE_AUTH_TYPE) AS AUTH_TYPE ,RE.RIP_STATUS ,FN_GET_CODENM('VOC0022' , RE.RIP_STATUS) AS RIP_STATUS_NM ,RE.REG_RSN ,FN_GET_CODENM('VOC0023' , RE.REG_RSN) AS REG_RSN_NM ,TO_CHAR(RE.REGST_DTTM , 'YYYY-MM-DD HH24:MI' ) AS REG_DTTM ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RE.REGST_ID) AS REGST_NM ,TO_CHAR(RE.RVISN_DTTM , 'YYYY-MM-DD HH24:MI' ) AS RVISN_DTTM ,(SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = RE.RVISN_ID) AS RVISN_NM FROM MSP_REUSE_IP_MST RE ,MSP_JUO_SUB_INFO SUB ,MSP_REQUEST_DTL REQ ,MSP_PARTNER_USIM_MST PUM ,MSP_REQUEST R ,NMCP_USIM_BUY_TXN@DL_MCP MSD WHERE RE.CONTRACT_NUM = SUB.CONTRACT_NUM AND RE.CONTRACT_NUM = REQ.CONTRACT_NUM AND REQ.FST_USIM_NO = PUM.USIM_NO(+) AND SUB.ICC_ID = MSD.REQ_USIM_SN(+) AND REQ.CONTRACT_NUM = R.CONTRACT_NUM(+) AND REQ.RES_NO = R.RES_NO(+)
AND RE.REGST_DTTM BETWEEN TO_DATE(#{strtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDt} || '235959', 'YYYYMMDDHH24MISS')
AND RE.RIP_STATUS = #{pRipStatus}
AND RE.CONTRACT_NUM = #{searchName}
AND SUB.SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND RE.RIP LIKE '%' || #{searchName} || '%'
ORDER BY RE.REGST_DTTM DESC

mapper.update:
/* ReuseRipMgmtMapper.updateReuseRipMst */
UPDATE MSP_REUSE_IP_MST
	SET RIP_STATUS = #{ripStatus}
	      ,REG_RSN = #{regRsn}
	      ,RVISN_ID = #{sessionUserId}
		 ,RVISN_DTTM = SYSDATE
	WHERE REUSE_IP_SEQ = #{reuseIpSeq}

mapper.insert:
		/* ReuseRipMgmtMapper.insertReuseRipUpdHist */
	INSERT INTO MSP_REUSE_IP_HIST(
			CONTRACT_NUM
			,RIP
			,RIP_STATUS
			,REG_RSN
            ,RATE_CD
            ,SUB_STATUS
			,REGST_ID
			,REGST_DTTM
		)VALUES(
			#{contractNum, jdbcType=VARCHAR}
			,(SELECT RIP FROM MSP_REUSE_IP_MST WHERE REUSE_IP_SEQ  = #{reuseIpSeq , jdbcType=VARCHAR})
			,#{ripStatus, jdbcType=VARCHAR}
			,#{regRsn, jdbcType=VARCHAR}
            ,#{lstRateCd, jdbcType=VARCHAR}
            ,#{subStatus, jdbcType=VARCHAR}
			,#{sessionUserId}
			, SYSDATE
		)

